UPDATE public.blog_posts SET
  content = E'Roteiro de 3 dias em Ilha Grande pensado para quem quer ver o melhor sem correria.\n\n## Dia 1 — Chegada e Vila do Abraão\n- Check-in e almoço na vila.\n- Caminhada até Praia Preta e Abraãozinho.\n- Pôr do sol no cais.\n\n## Dia 2 — Volta à Ilha\n- Escuna: Lagoa Azul, Freguesia, Saco do Céu, Aventureiro.\n- Almoço a bordo.\n\n## Dia 3 — Lopes Mendes\n- Barco até Pouso + trilha (20 min).\n- Tarde livre na praia.\n- Retorno.\n\n## Dicas\n- Reserve transfer e passeios pelo WhatsApp.\n- Dinheiro em espécie.\n- Sapato fechado nas trilhas.',
  reading_minutes = 6,
  cover_image = 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?auto=format&fit=crop&w=1600&q=80'
WHERE slug = 'o-que-fazer-em-ilha-grande-em-3-dias';

