UPDATE public.blog_posts SET
  content = E'Quanto custa uma viagem para Ilha Grande? Faixa realista por pessoa, 4 dias na alta temporada:\n\n- **Transfer Rio → Ilha (ida e volta):** R$ 200 – R$ 350\n- **Hospedagem:** R$ 120 (hostel) a R$ 700 (boutique) por noite\n- **Alimentação:** R$ 100 – R$ 200 por dia\n- **Passeios:** R$ 150 – R$ 250 por passeio\n\n**Total estimado:** R$ 1.500 a R$ 4.500 por pessoa em 4 dias.\n\n## Como economizar\n- Viaje na baixa temporada (abr–jun, set–nov).\n- Prefira hostels e cozinhe parte das refeições.\n- Escunas coletivas.\n- Reserve com antecedência.',
  reading_minutes = 5,
  cover_image = 'https://images.unsplash.com/photo-1469854523086-cc02fe5d8800?auto=format&fit=crop&w=1600&q=80'
WHERE slug = 'quanto-custa-viajar-para-ilha-grande';

UPDATE public.blog_posts SET
  content = E'Saindo de São Paulo, o trajeto até Ilha Grande tem 460–530 km e leva 6 a 8 horas.\n\n## De carro\n- BR-116 → Rio → BR-101 (Rio-Santos) até Angra ou Conceição de Jacareí.\n- Estacionamento privado no cais (R$ 40–80/dia).\n\n## De ônibus\n- SP → Angra dos Reis (~7h), depois barca/catamarã.\n\n## De avião + transfer\n- Voe até Rio (GIG ou SDU) e contrate transfer porta a porta.\n\n> Combos São Paulo → Ilha Grande pelo WhatsApp da Estação Ilha Grande.',
  reading_minutes = 5,
  cover_image = 'https://images.unsplash.com/photo-1494976388531-d1058494cdd8?auto=format&fit=crop&w=1600&q=80'
WHERE slug = 'como-chegar-em-ilha-grande-saindo-de-sao-paulo';

UPDATE public.blog_posts SET
  content = E'A Praia do Aventureiro é o cartão-postal de Ilha Grande, com o coqueiro inclinado e paisagem selvagem.\n\n## Como chegar\n- Escuna do Abraão (~2h30).\n- Jipe + barco pelo sul.\n\n## O que esperar\n- Comunidade caiçara com pousadas simples.\n- Mar calmo, areia clara.\n- Sem grandes estruturas — leve dinheiro.\n\n## Dicas\n- Saia cedo.\n- Leve protetor, água e câmera.\n- Respeite a reserva.',
  reading_minutes = 5,
  cover_image = 'https://images.unsplash.com/photo-1602002418082-a4443e081dd1?auto=format&fit=crop&w=1600&q=80'
WHERE slug = 'guia-praia-do-aventureiro';

