UPDATE public.blog_posts SET
  content = E'A Lagoa Verde é uma piscina natural rasa de águas esverdeadas, ideal para snorkel.\n\n## Como chegar\n- Lancha ou escuna a partir do Abraão (~30 min).\n- Frequentemente combinada com Lagoa Azul.\n\n## Por que vale\n- Água parada, transparente e rasa.\n- Vida marinha visível.\n\n## Dicas\n- Leve máscara própria.\n- Protetor biodegradável.\n- Vá cedo.',
  reading_minutes = 4,
  cover_image = 'https://images.unsplash.com/photo-1520454974749-611b7248ffdb?auto=format&fit=crop&w=1600&q=80'
WHERE slug = 'guia-lagoa-verde';

UPDATE public.blog_posts SET
  content = E'O Pico do Papagaio (982m) é o ponto mais alto de Ilha Grande, com vista 360º.\n\n## Como subir\n- Trilha de 6 a 8h (ida + volta).\n- Subida íngreme, corda fixa no topo.\n- **Obrigatório guia credenciado**.\n\n## O que levar\n- 3L de água\n- Lanche energético\n- Tênis de trilha\n- Lanterna de cabeça\n- Capa de chuva\n\n## Dicas\n- Saia antes do amanhecer.\n- Em dias chuvosos, a trilha é interditada.\n- Não é trilha para iniciantes.',
  reading_minutes = 6,
  cover_image = 'https://images.unsplash.com/photo-1551632811-561732d1e306?auto=format&fit=crop&w=1600&q=80'
WHERE slug = 'guia-pico-do-papagaio';

