UPDATE public.blog_posts SET
  content = E'Melhor época para visitar Ilha Grande:\n\n- **Dez – Mar:** alta temporada, clima quente, ilha cheia.\n- **Abr – Jun:** clima ameno, ilha vazia, melhor custo-benefício.\n- **Jul:** férias escolares.\n- **Set – Nov:** dias estáveis, ótimo para trilhas e mergulho.\n\n## Chuvas\nVerão é úmido. Inverno mais seco.\n\n## Mar\nMelhor visibilidade de abril a outubro.\n\n## Conclusão\nPraia e festa: alta temporada. Natureza e silêncio: abr/mai/set/out.',
  reading_minutes = 4,
  cover_image = 'https://images.unsplash.com/photo-1493558103817-58b2924bce98?auto=format&fit=crop&w=1600&q=80'
WHERE slug = 'melhor-epoca-para-visitar-ilha-grande';

