UPDATE public.blog_posts SET
  content = E'Choveu em Ilha Grande?\n\n- Bares e restaurantes da vila com música ao vivo.\n- Museu do Cárcere em Dois Rios.\n- Escuna esperando a chuva parar.\n- Sessões em pousadas.\n- Aquário Natural.\n\n## Dicas\n- Capa de chuva sempre na mochila.\n- Evite trilhas longas em chuva forte.\n- Confira a Capitania antes de embarcar.',
  reading_minutes = 4,
  cover_image = 'https://images.unsplash.com/photo-1530631673369-bc20fdb32288?auto=format&fit=crop&w=1600&q=80'
